<template>
  <div>
    <p style="margin-bottom: 12px;" v-if="data.length > 0">
      排名
      <a-switch @click="rankChange" v-model="rank" style="margin-right: 20px;"/>
      展示详情
      <a-switch v-model="showDetails"/>
    </p>
    <p style="text-align: center;" v-else-if="loading">加载中</p>
    <a-list :grid="{ gutter: 16, column: 1 }" :data-source="rank ? dataRanked : data" v-if="!loading">
      <a-list-item slot="renderItem" slot-scope="item">
        <a-card :title="`${item.contestantName}` + (item.description ? `（${item.description}）` : '')">
          <h2 slot="extra" style="margin: 0;">{{ scoreResult(result(item.judgeScoreRecords)) }}分</h2>
          <a-row :gutter="[16, 0]" v-if="showDetails">
            <!-- <pre>{{ result(item.judgeScoreRecords) }}</pre> -->
            <a-col v-for="(itemScore, index) in handleResult(result(item.judgeScoreRecords))" :key="index" :xs="24" :sm="24" :md="12" :lg="12" :xl="8" :xxl="6">
              <a-card style="width: 100%; margin-bottom: 20px; border-radius: 8px; height: 140px;">
                <h4 slot="title" style="margin: 0;">
                  <a-icon :type="itemScore.judgeId ? 'user' : 'team'"/>{{ itemScore.judgeId ? `${itemScore.judgeName}` : `${itemScore.groupName}` }}
                </h4>
                <h2 slot="extra" style="margin: 0;">
                  {{ itemScore.judgeId ? itemScore.score.toFixed(2) : avgScore(itemScore.scoreRecords.map(r => r.score), itemScore.withHLestScore).toFixed(2) }}分
                </h2>
                <div v-if="itemScore.judgeId">
                  <p style="color: #6666ff">{{ `${itemScore.groupName}，权重为${itemScore.groupWeight}` }}</p>
                  <p style="color: #00cc00">权重分：{{ (itemScore.score * itemScore.groupWeight).toFixed(2) }}分</p>
                </div>
                <div v-else-if="itemScore.scoreRecords.length > 0">
                  <p v-if="itemScore.withHLestScore">已去掉最高分和最低分</p>
                  <p style="color: #6666ff">权重为{{ itemScore.scoreRecords[0].groupWeight }}，当前已有{{ itemScore.scoreRecords.length }}人评分</p>
                  <p style="color: #00cc00">权重分：{{ (avgScore(itemScore.scoreRecords.map(r => r.score), itemScore.withHLestScore) * itemScore.scoreRecords[0].groupWeight).toFixed(2) }}分</p>
                </div>
              </a-card>
            </a-col>
          </a-row>
        </a-card>
      </a-list-item>
    </a-list>
  </div>
</template>
<script>
import { getContestantScores } from '@/api/dataAnalysis'
import { getContestantScoreDetail } from '@/api/scoreRecord'
import { voteGroupList } from '@/api/judgeGroup'
const config = [
  {
    groupName: '评委1组',
    showAll: true,
    withHLestScore: false,
  },
  {
    groupName: '评委2组-陈孝海',
    showAll: true,
    withHLestScore: false,
  },
  {
    groupName: '评委2组-任佳',
    showAll: true,
    withHLestScore: false,
  },
  {
    groupName: '评委2组-王林',
    showAll: true,
    withHLestScore: false,
  },
  {
    groupName: '评委2组-何彬',
    showAll: true,
    withHLestScore: false,
  },
  {
    groupName: '评委2组-其他领导',
    showAll: false,
    withHLestScore: false,
  },
  {
    groupName: '大众评委',
    showAll: false,
    withHLestScore: true,
  },
]

const avgScore = (scores, withHLestScore) => {
  if (scores.length === 0) {
    return 0
  } else if (scores.length === 1) {
    return scores[0]
  } else if (scores.length === 2) {
    return (scores[0] + scores[1]) / 2
  } else {
    const sortedScores = scores.slice().sort((a, b) => a - b)
    if (withHLestScore) {
      sortedScores.pop()
      sortedScores.shift()
    }
    const total = sortedScores.reduce((sum, score) => sum + score, 0)
    return total / sortedScores.length
  }
}

const result = (scoreRecords) => {
  var classify = []
  config.forEach(item => {
    classify.push({
      groupName: item.groupName,
      showAll: item.showAll,
      withHLestScore: item.withHLestScore,
      scoreRecords: scoreRecords.filter(scoreRecord => scoreRecord.groupName === item.groupName),
    })
  })
  return classify
}

const handleResult = (result) => {
  var handeledData = []
  result.forEach(item => {
    if (item.showAll) {
      item.scoreRecords.forEach(scoreRecordItem => {
        handeledData.push(scoreRecordItem)
      })
    } else if (item.scoreRecords.length > 0) {
      handeledData.push(item)
    }
  })
  return handeledData
}

const scoreResult = (classifyResult) => {
  var result = 0
  classifyResult.forEach(item => {
    if (item.scoreRecords.length > 0) {
      const weight = item.scoreRecords[0].groupWeight
      result += Number((avgScore(item.scoreRecords.map(r => r.score), item.withHLestScore) * weight).toFixed(2))
    }
  })
  return result.toFixed(2)
}
export default {
  data() {
    return {
      data: [],
      dataRanked: [],
      groupData: [],
      loading: false,
      rank: false,
      scoreTemp: [],
      showDetails: false,
      result,
      avgScore,
      handleResult,
      scoreResult,
    }
  },
  mounted() {
    this.loadData()
  },
  methods: {
    async loadData() {
      console.log(typeof this.$route.params.id)
      if (this.$route.params.id.toString() !== '7') {
        this.$message.info(`${typeof this.$route.params.id} ${this.$route.params.id} 当前统计方式系2026上半年数据建模比赛专用`)
        this.$router.go(-1)
      }
      this.loading = true
      // try {
      //   const res = await getContestantScores(this.$route.params.id)
      //   voteGroupList(this.$route.params.id).then(res => {
      //     this.groupData = res.records
      //   })
      //   const sortTemp = res.map(item => item.contestantId)
      //   var tempData = await Promise.all(
      //     res.map(item => getContestantScoreDetail(this.$route.params.id, item.contestantId))
      //   )
      //   console.log(1, tempData)
      //   tempData.sort((a, b) => sortTemp.indexOf(a.contestantId) - sortTemp.indexOf(b.contestantId))
      //   console.log(2, tempData)
      //   this.data = tempData
      //   this.scoreTemp = tempData.map(item => scoreResult(result(item.judgeScoreRecords)))
      //   this.dataRanked = tempData.sort((a, b) => scoreResult(result(b.judgeScoreRecords)) - scoreResult(result(a.judgeScoreRecords)))
      // } catch (error) {
      //   console.error('加载数据失败:', error)
      // } finally {
      //   this.loading = false
      // }
      try {
        const [scoresRes, groupRes] = await Promise.all([
          getContestantScores(this.$route.params.id),
          voteGroupList(this.$route.params.id),
        ])

        this.groupData = groupRes.records
        const detailPromises = scoresRes.map(item =>
          getContestantScoreDetail(this.$route.params.id, item.contestantId)
        )
        let tempData = await Promise.all(detailPromises)
        console.log(1, tempData)
        const sortMap = new Map()
        scoresRes.forEach((item, index) => {
          sortMap.set(item.contestantId, index)
        })
        tempData = tempData.filter(item => sortMap.has(item.contestantId))
        tempData.sort((a, b) => {
          const indexA = sortMap.get(a.contestantId)
          const indexB = sortMap.get(b.contestantId)
          return indexA - indexB
        })
        console.log(2, tempData)
        this.data = tempData
        this.scoreTemp = tempData.map(item => scoreResult(result(item.judgeScoreRecords)))
        this.dataRanked = [...tempData].sort((a, b) =>
          scoreResult(result(b.judgeScoreRecords)) - scoreResult(result(a.judgeScoreRecords))
        )
      } catch (error) {
        console.error('加载数据失败:', error)
      } finally {
        this.loading = false
      }
    },
    rankChange(e) {
      this.$router.replace({ query: { rank: e } })
    },
  },
}
</script>
<style lang="less" scoped>
p {
  margin: 0;
}
::v-deep .ant-card-head-title {
  font-size: 22px;
}
::v-deep .ant-card-body {
  padding: 16px 16px 12px !important;
}
::v-deep .ant-card-head {
  padding: 0 12px;
}
::v-deep .ant-card-head-title {
  padding: 8px 0;
}
::v-deep .ant-card-extra {
  padding: 8px 0;
}
</style>
