import request from '@/utils/request'

export function getContestantScores(voteId) {
  return request({
    url: `/data-analysis/contestant-scores?voteId=${voteId}`,
    method: 'get',
  })
}

export function getContestantScoresRanked(voteId) {
  return request({
    url: `/data-analysis/contestant-scores-ranked?voteId=${voteId}`,
    method: 'get',
  })
}

export function getContestantScoresWithoutRemoving(voteId) {
  return request({
    url: `/data-analysis/contestant-scores-without-removing?voteId=${voteId}`,
    method: 'get',
  })
}

export function getContestantScoresRankedWithoutRemoving(voteId) {
  return request({
    url: `/data-analysis/contestant-scores-without-removing-ranked?voteId=${voteId}`,
    method: 'get',
  })
}
